#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding dyslexia-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    preferred_name:string! \
    gender_identity:string! \
    ethnicity:string! \
    preferred_language:string! \
    interpreter_required:string! \
    gp_name:string! \
    gp_practice:string! \
    referrer_name:string! \
    referrer_role:string! \
    --htmx

cargo loco generate scaffold assessment_developmental_history \
    assessment:references \
    birth_complications:string! \
    birth_complications_details:text! \
    speech_delay:string! \
    speech_delay_details:text! \
    motor_delay:string! \
    motor_delay_details:text! \
    family_history_dyslexia:string! \
    family_history_details:text! \
    family_history_other_learning_difficulties:string! \
    family_history_other_details:text! \
    hearing_concerns:string! \
    hearing_concerns_details:text! \
    vision_concerns:string! \
    vision_concerns_details:text! \
    developmental_notes:text! \
    --htmx

cargo loco generate scaffold assessment_educational_background \
    assessment:references \
    current_education_level:string! \
    school_name:string! \
    year_group:string! \
    previous_schools_count:int \
    school_attendance:string! \
    academic_performance:string! \
    english_as_additional_language:string! \
    additional_languages:text! \
    sen_register:string! \
    ehcp:string! \
    ehcp_details:text! \
    educational_notes:text! \
    --htmx

cargo loco generate scaffold assessment_reading \
    assessment:references \
    reading_fluency_score:int \
    reading_comprehension_score:int \
    single_word_reading_score:int \
    nonword_reading_score:int \
    reading_speed:string! \
    reading_accuracy:string! \
    reading_avoidance:string! \
    reading_fatigue:string! \
    reading_notes:text! \
    --htmx

cargo loco generate scaffold assessment_writing_spelling \
    assessment:references \
    spelling_score:int \
    written_expression_score:int \
    handwriting_quality:string! \
    handwriting_speed:string! \
    spelling_error_pattern:string! \
    sentence_structure:string! \
    punctuation_use:string! \
    writing_avoidance:string! \
    writing_notes:text! \
    --htmx

cargo loco generate scaffold assessment_phonological_processing \
    assessment:references \
    phonological_awareness_score:int \
    phonological_memory_score:int \
    rapid_naming_score:int \
    rhyme_detection:string! \
    phoneme_segmentation:string! \
    phoneme_blending:string! \
    phoneme_manipulation:string! \
    rapid_naming_difficulty:string! \
    phonological_notes:text! \
    --htmx

cargo loco generate scaffold assessment_working_memory_processing_speed \
    assessment:references \
    working_memory_score:int \
    processing_speed_score:int \
    digit_span_forward:int \
    digit_span_backward:int \
    following_instructions:string! \
    task_completion_speed:string! \
    organisational_skills:string! \
    concentration_difficulties:string! \
    concentration_details:text! \
    working_memory_notes:text! \
    --htmx

cargo loco generate scaffold assessment_emotional_behavioural \
    assessment:references \
    self_esteem:string! \
    anxiety_about_learning:string! \
    anxiety_details:text! \
    frustration_with_tasks:string! \
    frustration_details:text! \
    avoidance_behaviours:string! \
    avoidance_details:text! \
    peer_relationships:string! \
    behavioural_concerns:string! \
    behavioural_concerns_details:text! \
    motivation_for_learning:string! \
    emotional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_previous_support \
    assessment:references \
    previous_assessments:string! \
    previous_assessments_details:text! \
    previous_diagnosis:string! \
    previous_diagnosis_details:text! \
    school_interventions:string! \
    school_interventions_details:text! \
    speech_therapy:string! \
    speech_therapy_details:text! \
    occupational_therapy:string! \
    occupational_therapy_details:text! \
    assistive_technology:string! \
    assistive_technology_details:text! \
    exam_access_arrangements:string! \
    exam_access_details:text! \
    support_notes:text! \
    --htmx

cargo loco generate scaffold assessment_recommendations \
    assessment:references \
    specialist_teaching:string! \
    specialist_teaching_details:text! \
    classroom_accommodations:string! \
    classroom_accommodations_details:text! \
    assistive_technology_recommended:string! \
    assistive_technology_recommended_details:text! \
    exam_access_recommended:string! \
    exam_access_recommended_details:text! \
    further_referrals:string! \
    further_referrals_details:text! \
    review_date:date \
    recommendations_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    severity_level:string! \
    lowest_domain_score:int \
    lowest_domain_name:string! \
    overall_risk_level:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
